        content: "Laravel routing e definit în `routes/web.php` și `routes/api.php`.\n\n```php\n<?php\nuse App\\Http\\Controllers\\UserController;\nuse App\\Http\\Controllers\\ProdusController;\nuse Illuminate\\Support\\Facades\\Route;\n\n// Route simple:\nRoute::get('/', function () {\n    return view('welcome'); // resources/views/welcome.blade.php\n});\n\nRoute::get('/despre', function () {\n    return 'Pagina despre noi';\n});\n\n// Route cu Controller:\nRoute::get('/users', [UserController::class, 'index']);\nRoute::post('/users', [UserController::class, 'store']);\nRoute::get('/users/{id}', [UserController::class, 'show']);\nRoute::put('/users/{id}', [UserController::class, 'update']);\nRoute::delete('/users/{id}', [UserController::class, 'destroy']);\n\n// Resource route — generează toate 7 route-uri CRUD dintr-o linie:\nRoute::resource('produse', ProdusController::class);\n// GET /produse          → index\n// GET /produse/create   → create\n// POST /produse         → store\n// GET /produse/{produs} → show\n// GET /produse/{produs}/edit → edit\n// PUT /produse/{produs} → update\n// DELETE /produse/{produs} → destroy\n\n// Grupare route-uri cu middleware:\nRoute::middleware('auth')->group(function () {\n    Route::get('/dashboard', [DashboardController::class, 'index']);\n    Route::resource('comenzi', ComandaController::class);\n});\n\n// Named routes:\nRoute::get('/profil', [ProfileController::class, 'show'])->name('profile.show');\n// În Blade: <a href=\"{{ route('profile.show') }}\">Profil</a>\n// În PHP: redirect()->route('profile.show')\n```",
