        content: "```php\n<?php\nuse App\\Models\\User;\n\n// CREATE — creare înregistrare:\n$user = User::create([\n    'name'     => 'Ion Popescu',\n    'email'    => 'ion@example.com',\n    'password' => bcrypt('parola123'),\n]);\necho $user->id; // ID-ul nou creat\n\n// SAU cu new + save:\n$user = new User();\n$user->name = 'Ion';\n$user->email = 'ion@example.com';\n$user->save();\n\n// READ — citire:\n$toti = User::all();                    // toți userii\n$user = User::find(42);                 // după ID sau null\n$user = User::findOrFail(42);           // sau 404\n$activi = User::where('activ', true)->get(); // cu filtru\n$primul = User::where('email', 'a@b.com')->first(); // primul match\n\n// UPDATE — actualizare:\n$user = User::find(42);\n$user->name = 'Ion Modificat';\n$user->save();\n// SAU bulk update:\nUser::where('activ', false)->update(['deleted_at' => now()]);\n\n// DELETE:\n$user = User::find(42);\n$user->delete();\n// SAU direct:\nUser::destroy(42);         // după ID\nUser::destroy([1, 2, 3]); // multiple IDs\nUser::where('activ', false)->delete(); // bulk\n\n// UPSERT — creare sau actualizare:\n$user = User::updateOrCreate(\n    ['email' => 'ion@example.com'],          // caută după\n    ['name' => 'Ion', 'activ' => true],      // setează\n);\n```",
