        content: "Relațiile sunt inima Eloquent. Definești în Model, Eloquent generează JOIN-urile automat.\n\n```php\n<?php\n// ONE-TO-MANY: Un User are mai multe Comenzi\nclass User extends Model {\n    public function comenzi(): \\Illuminate\\Database\\Eloquent\\Relations\\HasMany {\n        return $this->hasMany(Comanda::class);\n        // FK: comenzi.user_id\n    }\n    \n    public function profil(): \\Illuminate\\Database\\Eloquent\\Relations\\HasOne {\n        return $this->hasOne(Profil::class);\n    }\n}\n\nclass Comanda extends Model {\n    public function user(): \\Illuminate\\Database\\Eloquent\\Relations\\BelongsTo {\n        return $this->belongsTo(User::class);\n        // FK: comenzi.user_id\n    }\n}\n\n// UTILIZARE:\n$user = User::find(1);\n$comenziUser = $user->comenzi; // Collection de Comanda\nforeach ($user->comenzi as $comanda) {\n    echo $comanda->total;\n}\n\n// Invers:\n$comanda = Comanda::find(5);\necho $comanda->user->name; // Eloquent face JOIN automat\n\n// MANY-TO-MANY: Produse ↔ Taguri\nclass Produs extends Model {\n    public function taguri(): \\Illuminate\\Database\\Eloquent\\Relations\\BelongsToMany {\n        return $this->belongsToMany(Tag::class); // tabel pivot: produs_tag\n    }\n}\n\n// Atașare:\n$produs->taguri()->attach([1, 2, 3]); // adaugă taguri\n$produs->taguri()->sync([1, 4]);      // setează exact aceste taguri\n```",
